spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 10000;
    var progress = (t % duration) / duration;

    // Number digits: 4  2  .  3  7  5
    // Positions:     T  O  .  t  h  th
    var cols = ['Tens', 'Ones', '.', 'Tenths', 'Hund.', 'Thous.'];
    var digits = ['4', '2', '.', '3', '7', '5'];
    var numCols = cols.length;

    var colWidth = 42;
    var tableW = numCols * colWidth;
    var startX = (W - tableW) / 2;
    var startY = H / 2 - 25;
    var rowHeight = 30;

    // Determine active column
    var activeColIndex = -1;
    if (progress < 0.15) activeColIndex = 0; // Tens ('4')
    else if (progress >= 0.15 && progress < 0.30) activeColIndex = 1; // Ones ('2')
    else if (progress >= 0.30 && progress < 0.45) activeColIndex = 3; // Tenths ('3')
    else if (progress >= 0.45 && progress < 0.60) activeColIndex = 4; // Hundredths ('7')
    else if (progress >= 0.60 && progress < 0.75) activeColIndex = 5; // Thousandths ('5')

    // Draw Table Headers and Cells
    for (var i = 0; i < numCols; i++) {
      var cx = startX + i * colWidth;

      // Headers
      ctx.beginPath();
      ctx.rect(cx, startY, colWidth, rowHeight);
      ctx.fillStyle = '#1F2937';
      ctx.fill();
      ctx.strokeStyle = '#374151';
      ctx.lineWidth = 1.5;
      ctx.stroke();

      ctx.fillStyle = '#9CA3AF';
      ctx.font = 'bold 9px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(cols[i], cx + colWidth / 2, startY + rowHeight / 2);

      // Digits
      ctx.beginPath();
      ctx.rect(cx, startY + rowHeight, colWidth, rowHeight);

      var isActive = (i === activeColIndex);
      if (isActive) {
        ctx.fillStyle = '#8B5CF6'; // Purple highlight
      } else if (i === 2) {
        ctx.fillStyle = '#374151'; // Dot cell background
      } else {
        ctx.fillStyle = '#111827';
      }
      ctx.fill();
      ctx.stroke();

      ctx.fillStyle = isActive ? '#FFFFFF' : (i === 2 ? '#EF4444' : '#F3F4F6');
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillText(digits[i], cx + colWidth / 2, startY + rowHeight + rowHeight / 2);
    }

    // Description Text at bottom
    ctx.fillStyle = '#F3F4F6';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    if (activeColIndex === 0) {
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Digit 4 is in the Tens place', W / 2, H - 45);
      ctx.fillStyle = '#A78BFA';
      ctx.font = '13px -apple-system, sans-serif';
      ctx.fillText('Value = 4 × 10 = 40', W / 2, H - 22);
    } else if (activeColIndex === 1) {
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Digit 2 is in the Ones place', W / 2, H - 45);
      ctx.fillStyle = '#A78BFA';
      ctx.font = '13px -apple-system, sans-serif';
      ctx.fillText('Value = 2 × 1 = 2', W / 2, H - 22);
    } else if (activeColIndex === 3) {
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Digit 3 is in the Tenths place', W / 2, H - 45);
      ctx.fillStyle = '#A78BFA';
      ctx.font = '13px -apple-system, sans-serif';
      ctx.fillText('Value = 3 × 0.1 = 0.3 (or 3/10)', W / 2, H - 22);
    } else if (activeColIndex === 4) {
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Digit 7 is in the Hundredths place', W / 2, H - 45);
      ctx.fillStyle = '#A78BFA';
      ctx.font = '13px -apple-system, sans-serif';
      ctx.fillText('Value = 7 × 0.01 = 0.07 (or 7/100)', W / 2, H - 22);
    } else if (activeColIndex === 5) {
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Digit 5 is in the Thousandths place', W / 2, H - 45);
      ctx.fillStyle = '#A78BFA';
      ctx.font = '13px -apple-system, sans-serif';
      ctx.fillText('Value = 5 × 0.001 = 0.005 (or 5/1000)', W / 2, H - 22);
    } else {
      // Full Expansion view
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillText('Standard Form: 42.375', W / 2, H - 45);
      ctx.fillStyle = '#34D399';
      ctx.font = 'bold 12px -apple-system, sans-serif';
      ctx.fillText('Expanded: 40 + 2 + 0.3 + 0.07 + 0.005', W / 2, H - 22);
    }
  }
};
